# 1. 토큰 발급
curl -X POST https://iam.kakaocloud.com/identity/v3/auth/tokens \
  -H "Content-Type: application/json" \
  -d '{
    "auth": {
      "identity": {
        "methods": ["application_credential"],
        "application_credential": {
          "id": "YOUR_ACCESS_KEY_ID",
          "secret": "YOUR_SECRET_KEY"
        }
      }
    }
  }' \
  -i  # X-Subject-Token 헤더에서 토큰 확인

# 2. 토큰으로 API 호출
curl -X GET https://bcs.kr-central-2.kakaocloud.com/api/v1/instances \
  -H "X-Auth-Token: {발급받은_토큰}" \
  -H "Content-Type: application/json"
